import{_ as t,a,b as n,c as l,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as c}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"เพิ่ม Telegram Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/telegram.md","filePath":"th-TH/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"th-TH/upload/telegram.md"};function s(p,e,m,b,g,u){return d(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="เพิ่ม-telegram-channel" tabindex="-1">เพิ่ม Telegram Channel <a class="header-anchor" href="#เพิ่ม-telegram-channel" aria-label="Permalink to &quot;เพิ่ม Telegram Channel&quot;">​</a></h1><h2 id="สิ่งที่ต้องเตรียมก่อนเริ่ม" tabindex="-1">สิ่งที่ต้องเตรียมก่อนเริ่ม <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อนเริ่ม" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อนเริ่ม&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Telegram account</td><td>ใช้สร้าง bot และ storage channel</td></tr><tr><td><code>@BotFather</code></td><td>ใช้สร้าง Telegram bot</td></tr><tr><td>Telegram channel</td><td>ปลายทางสุดท้ายสำหรับเก็บ files</td></tr><tr><td><code>@userinfobot</code></td><td>ใช้ดู <code>Chat ID</code> ของ channel</td></tr></tbody></table><h2 id="เพิ่มได้จากที่ไหน" tabindex="-1">เพิ่มได้จากที่ไหน <a class="header-anchor" href="#เพิ่มได้จากที่ไหน" aria-label="Permalink to &quot;เพิ่มได้จากที่ไหน&quot;">​</a></h2><ol><li>เปิด System Settings</li><li>ไปที่ Upload Settings</li><li>คลิก Add Channel ที่มุมขวาบน</li><li>เลือก <code>Telegram</code></li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>ใช้ทำอะไร</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ชื่อที่จำง่ายสำหรับ channel นี้ เช่น &quot;Telegram Primary&quot;</td><td>Required</td></tr><tr><td>Active</td><td>เปิดหรือปิด channel นี้</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Token ของ Telegram bot</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>ID ของ Telegram channel</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>ใช้เฉพาะเมื่อเข้าถึง Telegram ไม่เสถียร ใส่ proxy URL แบบเต็มรวม <code>https://</code></td><td>Optional</td></tr><tr><td>Remark</td><td>หมายเหตุสำหรับดูแลในภายหลัง</td><td>Optional</td></tr></tbody></table><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><h3 id="_1-สร้าง-telegram-bot" tabindex="-1">1. สร้าง Telegram Bot <a class="header-anchor" href="#_1-สร้าง-telegram-bot" aria-label="Permalink to &quot;1. สร้าง Telegram Bot&quot;">​</a></h3><ol><li>เปิด Telegram แล้วค้นหา <code>@BotFather</code></li><li>เปิด chat แล้วคลิก <code>Start</code></li><li>ส่ง <code>/newbot</code></li><li>ทำตาม prompt เพื่อใส่ bot display name</li><li>ทำตาม prompt เพื่อใส่ bot username โดยปกติ username ต้องลงท้ายด้วย <code>bot</code></li><li>เมื่อสร้าง bot แล้ว <code>@BotFather</code> จะส่ง bot token กลับมา</li></ol><p>Token นี้คือค่า <code>Bot Token</code> ที่ต้องใส่ใน ImgBed</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-สร้าง-channel" tabindex="-1">2. สร้าง Channel <a class="header-anchor" href="#_2-สร้าง-channel" aria-label="Permalink to &quot;2. สร้าง Channel&quot;">​</a></h3><ol><li>ใน Telegram ให้คลิก New Channel</li><li>ใส่ channel name</li><li>สร้าง channel ให้เสร็จ</li></ol><p>ใช้ได้ทั้ง public และ private channel</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-เพิ่ม-bot-เข้า-channel" tabindex="-1">3. เพิ่ม Bot เข้า Channel <a class="header-anchor" href="#_3-เพิ่ม-bot-เข้า-channel" aria-label="Permalink to &quot;3. เพิ่ม Bot เข้า Channel&quot;">​</a></h3><ol><li>เปิด channel ที่เพิ่งสร้าง</li><li>เปิด channel settings</li><li>เพิ่ม member หรือ administrator</li><li>ค้นหา bot username ที่สร้างไว้</li><li>เพิ่ม bot เข้า channel</li></ol><p>เพื่อให้อัปโหลดได้เสถียรที่สุด แนะนำให้ให้สิทธิ์ bot เป็น administrator</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-รับ-channel-id-ด้วย-user-info-get-id-idbot" tabindex="-1">4. รับ Channel ID ด้วย User Info - Get ID - IDbot <a class="header-anchor" href="#_4-รับ-channel-id-ด้วย-user-info-get-id-idbot" aria-label="Permalink to &quot;4. รับ Channel ID ด้วย User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>ค้นหา <code>@userinfobot</code> ใน Telegram ชื่อที่แสดงมักเป็น <code>User Info - Get ID - IDbot</code></li><li>เปิด chat แล้วคลิก <code>Start</code></li><li>เลือก <code>Channel</code> จากตัวเลือกที่ bot ให้มา</li><li>ใน message picker ให้เลือก target channel แล้วส่งไปที่ <code>@userinfobot</code></li><li>เมื่อ <code>@userinfobot</code> ส่งผลลัพธ์กลับมา ให้ copy เลขที่แสดงเป็น <code>Id: -100...</code></li></ol><p>เลขที่ขึ้นต้นด้วย <code>-100</code> คือ <code>Session ID (Chat ID)</code> ที่ ImgBed ต้องใช้</p><p><img src="'+l+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-ใส่-telegram-channel-ใน-imgbed" tabindex="-1">5. ใส่ Telegram Channel ใน ImgBed <a class="header-anchor" href="#_5-ใส่-telegram-channel-ใน-imgbed" aria-label="Permalink to &quot;5. ใส่ Telegram Channel ใน ImgBed&quot;">​</a></h3><p>กลับไปที่ channel configuration dialog แล้วกรอกดังนี้:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>ชื่อ channel ที่ตั้งเอง เช่น <code>TelegramPrimary</code></td></tr><tr><td>Active</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Bot token จาก <code>@BotFather</code></td></tr><tr><td>Session ID (Chat ID)</td><td>เลข <code>-100...</code> ที่ได้จาก <code>@userinfobot</code></td></tr><tr><td>Relay Proxy URL (optional)</td><td>ใส่เฉพาะเมื่อจำเป็น เช่น <code>https://your-tg-proxy.example.com</code></td></tr><tr><td>Remark</td><td>หมายเหตุเพิ่มเติม</td></tr></tbody></table><p>กรอกครบแล้วคลิก Save</p><p><img src="'+o+`" alt="Edit the configuration" loading="lazy"></p><h2 id="วิธีตรวจสอบ" tabindex="-1">วิธีตรวจสอบ <a class="header-anchor" href="#วิธีตรวจสอบ" aria-label="Permalink to &quot;วิธีตรวจสอบ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>วิธีตรวจสอบ</th></tr></thead><tbody><tr><td>เห็น channel card</td><td>หลัง save หน้า Upload Settings ควรแสดง Telegram channel card</td></tr><tr><td>Channel เปิดใช้งานได้</td><td>Active switch ควรอยู่ในสถานะ on</td></tr><tr><td>Configuration ถูกบันทึก</td><td>Detail view ควรแสดงว่า Bot Token และ Chat ID ถูกบันทึกแล้ว</td></tr><tr><td>Upload ใช้งานได้</td><td>อัปโหลด test image แล้วตรวจสอบว่าไปปรากฏใน Telegram channel เป้าหมาย</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>สร้าง bot ด้วย @BotFather</span></span>
<span class="line"><span>-&gt; บันทึก Bot Token</span></span>
<span class="line"><span>-&gt; สร้าง Telegram channel</span></span>
<span class="line"><span>-&gt; เพิ่ม bot เข้า channel และให้สิทธิ์ administrator</span></span>
<span class="line"><span>-&gt; ค้นหา @userinfobot แล้วเลือก Channel</span></span>
<span class="line"><span>-&gt; Forward message ใดก็ได้จาก channel ไปที่ @userinfobot</span></span>
<span class="line"><span>-&gt; Copy ค่า Id: -100... ที่ได้กลับมา</span></span>
<span class="line"><span>-&gt; ใส่ Bot Token และ Chat ID ใน ImgBed</span></span>
<span class="line"><span>-&gt; Save แล้วอัปโหลด test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const T=r(h,[["render",s]]);export{k as __pageData,T as default};
